const b = $input.first().json.body || $input.first().json;
const missing = [];
if (!b.client_id) missing.push('client_id');
if (!b.website_url) missing.push('website_url');
if (missing.length) throw new Error(`Missing required fields: ${missing.join(', ')}`);
return [{ json: { client_id: b.client_id, website_url: b.website_url, industry: b.industry || null } }];

