// brand-strategist returns response.text containing JSON
const raw = $input.first().json.response || '';
const jsonMatch = raw.match(/\{[\s\S]*\}/);
if (!jsonMatch) throw new Error('Brand Strategist did not return parseable JSON');
const parsed = JSON.parse(jsonMatch[0]);
return [{ json: { ...parsed, client_id: $node['Validate Input'].json.client_id } }];

